#!/usr/bin/env python3
"""Build the interactive all-case analysis dashboard as a self-contained HTML."""
from __future__ import annotations

import csv
import json
from pathlib import Path

PROJECT = Path(__file__).resolve().parent.parent
CASES = PROJECT / "html" / "data" / "cases.json"
BENCH = PROJECT / "data" / "reference" / "official_round_benchmarks.csv"
OUTPUT = PROJECT / "html" / "analysis_dashboard.html"


KEEP = [
    "case_id", "round", "company", "target_entity", "scope", "local_pdf", "pdf_url",
    "project_cost_million_yen_normalized", "subsidy_million_yen_normalized", "subsidy_rate_pct",
    "sales_baseline_oku_yen", "sales_target_oku_yen", "sales_increase_oku_yen_normalized",
    "sales_growth_pct", "sales_cagr_pct", "sales_multiple", "sales_representative_scope",
    "labor_base_value_man_yen_per_person", "labor_target_value_man_yen_per_person", "labor_annual_rate_pct",
    "employee_pay_base_value_man_yen_per_person", "employee_pay_target_value_man_yen_per_person", "employee_pay_annual_rate_pct",
    "officer_pay_base_value_man_yen_per_person", "officer_pay_target_value_man_yen_per_person", "officer_pay_annual_rate_pct",
    "employees_base_value", "employees_target_value", "employees_annual_rate_pct",
    "employee_pay_total_base_estimated_oku", "employee_pay_total_target_estimated_oku",
    "employee_pay_total_increase_estimated_oku", "employee_pay_total_calculation_status",
    "employee_pay_total_period_alignment", "employee_pay_total_entity_alignment",
    "employee_pay_total_unit_validation", "employee_pay_total_increase_analysis_status",
    "page_count", "vision_page_count", "project_page_count", "quality_flag_count", "critical_quality_flag_count",
    "project_cost_analysis_status", "project_cost_analysis_reasons", "subsidy_analysis_status", "subsidy_analysis_reasons",
    "sales_values_analysis_status", "sales_values_analysis_reasons", "sales_rate_analysis_status", "sales_rate_analysis_reasons",
    "labor_values_analysis_status", "labor_values_analysis_reasons", "labor_rate_analysis_status", "labor_rate_analysis_reasons",
    "employee_pay_values_analysis_status", "employee_pay_values_analysis_reasons", "employee_pay_rate_analysis_status", "employee_pay_rate_analysis_reasons",
    "officer_pay_values_analysis_status", "officer_pay_values_analysis_reasons", "officer_pay_rate_analysis_status", "officer_pay_rate_analysis_reasons",
    "employees_values_analysis_status", "employees_values_analysis_reasons", "employees_rate_analysis_status", "employees_rate_analysis_reasons",
    "has_multiple_investments", "has_consortium", "has_parent_company_reference", "has_subsidiary_reference",
    "has_related_company_reference", "has_multiple_sales_series", "has_mixed_entity_metrics",
    "representative_entity_ambiguous", "has_ambiguous_rate_any", "has_period_ambiguity_any",
    "has_unit_ambiguity_any", "has_arithmetic_mismatch_any", "has_ocr_uncertainty_any",
    "analysis_exclusion_recommended", "analysis_exclusion_reasons",
]


def compact_case(row: dict) -> dict:
    out = {k: row.get(k) for k in KEEP}

    def derived_status(*keys: str) -> str:
        statuses = [row.get(f"{key}_analysis_status") for key in keys]
        if all(status == "ready" for status in statuses):
            return "ready"
        if all(status in {"ready", "usable_with_caution"} for status in statuses):
            return "usable_with_caution"
        if any(status == "review_required" for status in statuses):
            return "review_required"
        return "unavailable"

    cost = row.get("project_cost_million_yen_normalized")
    sales = row.get("sales_baseline_oku_yen")
    try:
        out["investment_sales_ratio_pct"] = round(float(cost) / float(sales), 3) if float(sales) else None
    except (TypeError, ValueError, ZeroDivisionError):
        out["investment_sales_ratio_pct"] = None
    out["investment_sales_ratio_analysis_status"] = derived_status("project_cost", "sales_values")

    return out


def main() -> None:
    cases = json.loads(CASES.read_text(encoding="utf-8"))
    rows = [compact_case(r) for r in cases]
    with BENCH.open(encoding="utf-8-sig", newline="") as fh:
        bench = list(csv.DictReader(fh))
    for r in bench:
        for k in ("applicant_value", "accepted_value", "applicant_n", "accepted_n"):
            try:
                r[k] = float(r[k])
            except (TypeError, ValueError):
                r[k] = None
    payload = json.dumps(rows, ensure_ascii=False, separators=(",", ":")).replace("</", "<\\/")
    bench_payload = json.dumps(bench, ensure_ascii=False, separators=(",", ":")).replace("</", "<\\/")
    html = TEMPLATE.replace("__DATA__", payload).replace("__BENCH__", bench_payload)
    OUTPUT.write_text(html, encoding="utf-8", newline="\n")
    print(f"wrote {OUTPUT} ({len(rows)} cases, {len(bench)} benchmark rows, {OUTPUT.stat().st_size:,} bytes)")


