 {no:6,key:'project_sales_increase',label:'補助事業売上高増加額',field:null,status:'unavailable',method:'補助事業だけの基準値・目標値を公開PDFから一貫して抽出できないため算出不可。'},
 {no:7,key:'labor_cagr',label:'年平均労働生産性の伸び',field:'labor_annual_rate_pct',status:'comparable',method:'企業別公開PDFに記載された年平均労働生産性の伸び率を使用。'},
